request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gateway ?gatewayName ?typeLabel ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:originalId ?origId .
  FILTER(STR(?origId) = "2aa476e4bbdf451083ec316570f7a3be")

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  { ?gateway a bboExt:ParallelGateway . }
  UNION
  { ?gateway a bboExt:ExclusiveGateway .
    ?gateway bboExt:gatewayDirection ?gd .
    FILTER(LCASE(STR(?gd)) = "diverging")
  }

  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  BIND( IF( EXISTS{ ?gateway a bboExt:ParallelGateway }, "ParallelGateway", "Exclusive+Diverging" ) AS ?typeLabel )

  ?gateway tai:belongsTo ?choreo .
}
LIMIT 25
